changeMonth = (month: number): void => {
  const monthSelectedIn = this.props.monthSelectedIn ?? 0;
  let monthDate: Date;

  this.setState(
    ({ date }) => {
      // When a day was selected in a later panel, `date` is the date in
      // that panel. Custom header navigation should still make the chosen
      // month the first visible panel, so retain the panel offset in the
      // calendar's internal anchor date.
      monthDate = setMonth(date, Number(month));
      return {
        date: addMonths(monthDate, monthSelectedIn),
      };
    },
    () => this.handleMonthChange(monthDate),
  );
};

